func PrintToJSON(sourcetext string, n *Node, opts t.ParseOptions) PrintResult {
	p := &printer{
		builder:    sourcemap.MakeChunkBuilder(nil, sourcemap.GenerateLineOffsetTables(sourcetext, len(strings.Split(sourcetext, "\n")))),
		sourcetext: sourcetext,
	}
	root := ASTNode{}
	renderNode(p, &root, n, opts)
	doc := root.Children[0]
	return PrintResult{
		Output: []byte(doc.String()),
	}
}

async function convertToCurrentColor(svg: SVG): Promise<void> {
  await parseColors(svg, {
    defaultColor: "currentColor",
    callback: (_, colorStr, color) => {
      return color === null || isEmptyColor(color) || isWhite(color)
        ? colorStr
        : "currentColor";
    },
  });
}

